    int n = 5;

    // ── Stack-allocated (fixed size, max ~10^6 elements) ──
    int arr[5] = {10, 20, 30, 40, 50};   // fully initialized
    int zeros[5] = {};                    // ALL zeros (value-initialize)
    int partial[5] = {1, 2};             // {1, 2, 0, 0, 0} — rest zero-filled

    // ── Reading into array ──
    int a[100005];
    for (int i = 0; i < n; i++) cin >> a[i];

    // ── Common access patterns ──
    cout << arr[0]        << "\n";  // first element
    cout << arr[n - 1]    << "\n";  // last element
    cout << arr[n / 2]    << "\n";  // middle element

    // ── Fill with a specific value (memset trick) ──
    int dp[100005];
    memset(dp, 0, sizeof(dp));       // fill with 0 (fastest)
    memset(dp, -1, sizeof(dp));      // fill with -1 (useful for memoization)
    // WARNING: memset(dp, 1, ...) does NOT set all to 1!
    // Use fill() instead:
    fill(dp, dp + n, 7);             // sets dp[0..n-1] = 7

    // ── Global arrays: auto-zero, up to ~10^8 bytes ──
    // Declare outside main for large arrays
    return 0;
}

