const int MAXV = 100005;   // max possible value
int freq[MAXV];            // global, auto-zero

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        int x; cin >> x;
        freq[x]++;           // count occurrences
    }

    // Query: how many times does value 5 appear?
    cout << freq[5] << "\n";

    // Find most frequent value
    int mode = max_element(freq, freq + MAXV) - freq;
    cout << "Mode: " << mode << " (" << freq[mode] << " times)\n";

    // Print all unique values
    for (int v = 0; v < MAXV; v++)
        if (freq[v] > 0)
            cout << v << " appears " << freq[v] << " times\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1005;
int grid[MAXN][MAXN];     // global 2D array — 1005×1005 ints ≈ 4 MB

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;  // rows, columns
    cin >> n >> m;
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++)
            cin >> grid[i][j];

    // ── Row-wise sum ──
    for (int i = 0; i < n; i++) {
        long long rowSum = 0;
        for (int j = 0; j < m; j++) rowSum += grid[i][j];
        cout << "Row " << i << " sum: " << rowSum << "\n";
    }

    // ── 4-directional neighbors (BFS/DFS pattern) ──
    int dx[] = {0, 0, 1, -1};  // right, left, down, up
    int dy[] = {1, -1, 0, 0};
    int r = 2, c = 3;           // example cell
    for (int d = 0; d < 4; d++) {
        int nr = r + dx[d], nc = c + dy[d];
        if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
            cout << "Neighbor: (" << nr << "," << nc << ") = " << grid[nr][nc] << "\n";
        }
    }

    // ── 2D Prefix Sum (range queries in O(1)) ──
    long long psum[MAXN][MAXN] = {};
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++)
            psum[i][j] = grid[i-1][j-1] + psum[i-1][j] + psum[i][j-1] - psum[i-1][j-1];
    // Sum of subgrid (r1,c1)–(r2,c2) [1-indexed]:
    // = psum[r2][c2] - psum[r1-1][c2] - psum[r2][c1-1] + psum[r1-1][c1-1]

    return 0;
}

